parameters.jsCode:
// Access the nested array
const tactics = $input.all()[0].json.output.tactics;

// Map them into the standard n8n { json: {} } format
return tactics.map(t => {
  return {
    json: {
      description: t.tactic_description
    }
  };
});

values.content:
=AI Video & Audio-Visual Prompt Engineer
Task: Analyze the provided input and generate a singular, high-fidelity cinematic video prompt. This prompt must harmonize the narration_snippet voiceover narration with complex, professional visual directing. The input data also contains the image_prompt that was used to generate an initial frame image. You also have access to a video prompt writing guide through a tool. You must use the tool when crafting an output prompt.

narration_snippet: {{ $json.narration_snippet }}
image_prompt: {{ $json.image_prompt }}

parameters.jsCode:
// 1. Get all incoming items
const items = $input.all();

// 2. Clean the data for valid items
items.forEach((item) => {
  if (item.json.output && item.json.output.narration_content) {
    item.json.output.narration_content = item.json.output.narration_content.replace(/\r|\n|\t/g, '');
  }
});

// 3. Return only items that have the 'output' property and NO 'error' property
return items.filter(item => {
  return item.json.output && !item.json.error;
});

